import { HashRouter, Routes, Route } from "react-router-dom";
import Myregister from "./register";
import Mylogin from "./login";
import { Link } from "react-router-dom";


const UserModule = () => {
  return (
    <HashRouter>
      <section className="bg-light p-3">
            <div className="container-fluid">
                <div className="row">
                    <div className="col-lg-6">
                        <h2> User Management System</h2> 
                    </div>

                    <div className="col-lg-6 text-end">
                    <Link className="nav-link btn btn-primary text-white" to="/register"><i className='fa fa-user-plus'></i> <i class="fa-regular fa-pen-to-square"></i> Create Account</Link>
                  
                    <Link className="nav-link text-white" to="/login"> <i className='fa fa-lock'></i>   Login</Link>
                    
                </div>
            </div>
            </div>
        </section>
    
      </HashRouter>
  );
};

export default UserModule;
